INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i08i05rllk9c3e8tkns4', 'cmp5neihn007ign7xhgk1gdd4', 'Борисов Арсений', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-04-17 07:48:19.632'),
('cmp67i08p05s5lk9cl3qo3adt', 'cmp5kx2pc000rgnzp2rh042jk', 'Миронов Эрик Сергеевич', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '2', 'Дошёл до сертификата, но устал от объёма чтения. Польза есть, но эмоций мало — скорее «отработал норму».', 't', '2026-04-10 15:41:19.732'),
('cmp67i04u05dtlk9cldu4xck1', 'cmp5neiio008rgn7xhy0papt5', 'Суздалов Николай', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Хороший рабочий курс: и лекции, и задания, и итоговый документ. Отняла балл только то, что к концу устала от однотипных формулировок в подсказках, но по содержанию всё честно и по делу.', 't', '2026-04-12 18:43:14.655'),
('cmp67i04y05e3lk9cd3ach0zx', 'cmp5kx2pe000ugnzps4nlvb5d', 'Пермяков Афанасий', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '5', 'Отлично структурировано: от простого к сложному, везде понятно, зачем этот шаг. Практика с ручной проверкой мотивировала не халтурить. После выдачи сертификата спокойно рассказываю одногруппникам, с чего начать ИБ.', 't', '2026-04-13 06:03:49.458'),
('cmp67i08l05rvlk9czfe7mzv0', 'cmp5neii1007xgn7xuaacpr3h', 'Кардашевский Андрей', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Хорошо стыкуется с тем, что проходим в группе. Прошла все модули, к итоговому документу вопросов нет. Минус балл за то, что AI-подсказки иногда слишком общие.', 't', '2026-04-13 20:02:58.038'),
('cmp67i08l05rxlk9cbfm1qj1d', 'cmp5neii40080gn7xr70onpv2', 'Кудинцева София', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Хорошо стыкуется с очным расписанием: можно догнать дома. Сертификат получил. Минус — иногда неочевидно, где сохранился черновик практики.', 't', '2026-04-12 20:12:46.885'),
('cmp67i05505etlk9c8qukwka9', 'cmp65v9cb00a3lksazsgbuo21', 'Горохова Алина', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-13 15:10:19.144'),
('cmp67i05a05fblk9cx29t2e9b', 'cmp5lt6z70010gnb9rksdecao', 'Слепцов Гаврил Алексеевич', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '3', 'В целом ок: прошёл, получил сертификат. Иногда не хватало короткого резюме после длинной лекции. Для базы по ИБ — нормально.', 't', '2026-04-08 09:59:26.978'),
('cmp67i05f05fplk9c42d44b1v', 'cmp66xht500bclktgqfgfgqdr', 'Ефимов Константин', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-22, 5 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-13 12:11:10.523'),
('cmp67i05n05gllk9c71crnrbh', 'cmp66xi6e00cilktgkuqry2ef', 'Иванов Станислав Яковлевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '5', 'На втором курсе ИСИП как раз то, что нужно: и термины, и аккуратные сценарии. Прошла полностью, сертификат уже в папке с документами. Рекомендую группе.', 't', '2026-04-12 06:25:57.026'),
('cmp67i05u05hflk9cgtau07hx', 'cmp66xijs00dolktgekkkx8uf', 'Винокуров Виталий Александрович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '3', 'Прошёл полностью, документ на руках. Нормальный уровень, без лишней воды. Хотелось бы чуть больше визуализации в лекциях.', 't', '2026-04-14 10:44:50.715'),
('cmp67i08j05rplk9chbt8jj2v', 'cmp5neihs007ogn7x3ip51d5u', 'Воронина Анастасия', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-04-11 20:57:43.191'),
('cmp67i08j05rrlk9c2hx1af1l', 'cmp5neihw007rgn7xwbgm9a8k', 'Габышев Альберт', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '2', 'Завершила курс из упрямства — в целом полезно, но ожидала большей гибкости по срокам и более разжёванных объяснений в паре модулей. За идею и сертификат спасибо, за подачу — на четвёрку не потянет.', 't', '2026-04-11 22:15:05.274'),
('cmp67i08n05rzlk9cy2kw6ge9', 'cmp5neii60083gn7xz2rercuf', 'Лебедева Арина', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-11 06:50:58.251'),
('cmp67i08o05s1lk9coy09ed32', 'cmp5neii90086gn7xpx1vachd', 'Марков Александр', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Хороший рабочий курс: и лекции, и задания, и итоговый документ. Отняла балл только то, что к концу устала от однотипных формулировок в подсказках, но по содержанию всё честно и по делу.', 't', '2026-04-13 18:09:50.387'),
('cmp67i08o05s3lk9c746zrsxm', 'cmp5neiib0089gn7xxtzqh5vp', 'Николаева Анжелика', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '2', 'Дошёл до сертификата, но устал от объёма чтения. Польза есть, но эмоций мало — скорее «отработал норму».', 't', '2026-04-12 23:40:31.5'),
('cmp67i06305idlk9ct89igksk', 'cmp5md5yw001fgnc0swwa2far', 'Дмитриев Айсен Артёмович', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '3', 'Прошла полностью, сертификат получила. В целом нормально: базу по ИБ собрала, тесты адекватные. Без восторга — иногда хотелось короче формулировок и больше живых примеров из учебной сети колледжа.', 't', '2026-04-12 18:08:38.058'),
('cmp67i06805ivlk9cjuvhs57v', 'cmp66xirr00folktgd6j01o16', 'Лебедева Лира Петровна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '2', 'Завершила курс из упрямства — в целом полезно, но ожидала большей гибкости по срокам и более разжёванных объяснений в паре модулей. За идею и сертификат спасибо, за подачу — на четвёрку не потянет.', 't', '2026-04-13 03:36:51.416'),
('cmp67i06b05j5lk9cy0e3qj2e', 'cmp66xis100g0lktgqoyqqo6i', 'Мордовской Алексей Александрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Прошла полностью, сертификат получила. В целом нормально: базу по ИБ собрала, тесты адекватные. Без восторга — иногда хотелось короче формулировок и больше живых примеров из учебной сети колледжа.', 't', '2026-04-13 11:11:42.32'),
('cmp67i06k05jzlk9clp2fiaw3', 'cmp66xiyv00h6lktgzw2dghcr', 'Бурнашов Руслан Игоревич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '5', 'Отлично выстроено под заочников: короткие сессии, понятные задания. Прошёл до конца без выгорания. Сертификат — приятное завершение.', 't', '2026-04-10 21:16:23.734'),
('cmp67i06r05ktlk9cwgack5vt', 'cmp5md60r001rgnc0ewvr8k77', 'Соколов Никита Викторович', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-12 10:59:38.795'),
('cmp67i06y05lnlk9cvn1dxqer', 'cmp66xj6600jflktgfei5wrid', 'Васильев Вячеслав Альбертович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '3', 'Прошла курс целиком. Нормально для программы: тесты честные, по практике комментарии полезные. Без «вау», но знания по ИБ реально прибавились.', 't', '2026-04-09 10:30:38.214'),
('cmp67i07805mllk9ckgtdr98k', 'cmp66xjda00krlktgk0h9l0sb', 'Семенов Юрий Михайлович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-12 12:35:13.082'),
('cmp67i07g05nflk9coil4elcz', 'cmp677s8u00lulk1v44yegf2u', 'Соколов Владислав Александрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '4', 'Удобно совмещать с работой: чёткие дедлайны по модулям не дают забросить. Сертификат получил. Минус — иногда долгая загрузка страниц, на контент не влияет.', 't', '2026-04-12 07:47:00.562'),
('cmp67i07o05odlk9ckdceq2se', 'cmp5mtbph0036gnh8nzj4vrac', 'Никифоров Артем', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '4', 'Прошёл курс до конца, материал связный. Практика с обратной связью — сильная сторона. Не идеально, но уверенная четвёрка.', 't', '2026-04-10 22:13:01.577');